// ============================================================
// Normalize Deck Structure - n8n Code Node
// ============================================================
// Takes raw Deck.json input and normalizes all cards to a
// consistent structure. Fixes typos, ensures every card and
// record has the same fields, and standardizes asset/prompt
// naming conventions.
// ============================================================

const input = $input.first().json;

// Handle both wrapped (data.Name) and unwrapped (Name) input
const deck = input.data || input;

// --- Configuration ---
const DECK_VERSION = 0.3;
const BASE_DIR = $('Set Global Parameters').first().json.CardsDir + '/';
const ORIENTATIONS = ['upright', 'reversed', 'between'];

// --- Helper: sanitize card name for file paths ---
function toFileSlug(name) {
  return name.replace(/[()]/g, '').replace(/\s+/g, '_');
}

// --- Helper: build asset filenames for a record ---
function buildRecordAssets(cardSlug, orientation) {
  return {
    Image: `IMG_${cardSlug}_${orientation}.png`,
    CardImage: `CARDIMG_${cardSlug}_${orientation}.png`,
    Narration: `NARRATION_${cardSlug}_${orientation}.mp3`,
    Music: `MUSIC_${cardSlug}_${orientation}.mp3`,
    Movie: `FOCUS_${cardSlug}_${orientation}.mpeg`,
    PalletImage: `PALLETEIMG_${cardSlug}_${orientation}.png`,
    Object: `MODEL_${cardSlug}_${orientation}.obj`,
    ObjectGLB: `MODEL_${cardSlug}_${orientation}.glb`,
    Object3DRef: `3DREF_${cardSlug}_${orientation}.png`
  };
}

// --- Helper: build image prompt template ---
function buildImagePrompts(cardName, orientation) {
  const otherOrientation = orientation === 'upright' ? 'reversed'
    : orientation === 'reversed' ? 'upright'
    : 'upright and reversed';
  return {
    Positive: `Describe the imagery and symbolism of the ${cardName} card in an ${orientation} position.`,
    Negative: `Describe the imagery and symbolism of the ${cardName} card in a ${otherOrientation} position.`
  };
}

// --- Helper: build narration prompt template ---
function buildNarrationPrompts(cardName, orientation) {
  return {
    Voice: 'Female',
    Tone: 'Warm and uplifting',
    Pace: 'Moderate',
    Volume: 'Medium',
    Emphasis: `Highlight the themes associated with the ${cardName} card in an ${orientation} position.`,
    'De-emphasis': `Avoid emphasizing aspects contrary to the ${orientation} orientation.`,
    Style: 'Narrate in a storytelling manner, engaging the listener with vivid descriptions.',
    Content: `Focus on the symbolism and meaning of the ${cardName} card in an ${orientation} position.`
  };
}

// --- Helper: build music prompt template ---
function buildMusicPrompts(cardName, orientation) {
  return {
    Tags: '',
    Lyrics: '[instrumental]',
    BPM: 0,
    KeyScale: ''
  };
}

// --- Helper: normalize a single record ---
function normalizeRecord(record, cardName, cardSlug, orientation) {
  const assets = buildRecordAssets(cardSlug, orientation);

  // Pull content from any existing nested location
  const existingAssets = record.Assets || record.assets || {};
  const existingPrompts = record.Prompts || record.prompts || {};

  return {
    Orientation: orientation,
    Description: record.Description || '',
    Meanings: Array.isArray(record.Meanings) ? record.Meanings : [],
    Keywords: Array.isArray(record.Keywords) ? record.Keywords : [],
    Advice: record.Advice || '',
    Affirmation: record.Affirmation || '',
    Category: Array.isArray(record.Category) ? record.Category : [],
    Assets: {
      Image: existingAssets.Image || assets.Image,
      CardImage: existingAssets.CardImage || assets.CardImage,
      Narration: existingAssets.Narration || assets.Narration,
      Music: existingAssets.Music || assets.Music,
      Movie: existingAssets.Movie || assets.Movie,
      PalletImage: existingAssets.PalletImage || assets.PalletImage,
      Object: existingAssets.Object || assets.Object,
      ObjectGLB: existingAssets.ObjectGLB || assets.ObjectGLB,
      Object3DRef: existingAssets.Object3DRef || assets.Object3DRef
    },
    Prompts: {
      Image: (existingPrompts.Image && existingPrompts.Image.Positive)
        ? existingPrompts.Image
        : buildImagePrompts(cardName, orientation),
      Narration: (existingPrompts.Narration && existingPrompts.Narration.Voice)
        ? existingPrompts.Narration
        : buildNarrationPrompts(cardName, orientation),
      Music: (existingPrompts.Music && existingPrompts.Music.Tags)
        ? existingPrompts.Music
        : buildMusicPrompts(cardName, orientation)
    }
  };
}

// --- Normalize deck-level assets (fix typo) ---
const deckAssets = {
  Directory: deck.Assets?.Directory || '',
  BackImage: deck.Assets?.BackImage || `${BASE_DIR}IMAGE_Deck_Back.png`,
  FrontImage: deck.Assets?.FrontImage || `${BASE_DIR}IMAGE_Deck_Front.png`,
  Music: deck.Assets?.Music || `${BASE_DIR}MUSIC_Deck.wav`,
  Narration: deck.Assets?.Narration || `${BASE_DIR}NARRATION_Deck.mp3`,
  Cut: deck.Assets?.Cut || `${BASE_DIR}CUT_Deck.mpg`,
  Fan: deck.Assets?.Fan || `${BASE_DIR}FAN_Deck.mpg`,
  Merge: deck.Assets?.Merge || `${BASE_DIR}MERGE_Deck.mpg`,
  Rotate: `${BASE_DIR}ROTATE_Deck.mpg`  // Fix: was ROTATE_mpg.png
};

// --- Normalize deck-level prompts ---
const deckPrompts = {};
const promptKeys = ['BackImage', 'FrontImage', 'Music', 'Narration', 'Cut', 'Fan', 'Merge', 'Rotate'];
for (const key of promptKeys) {
  const existing = deck.Prompts?.[key];
  deckPrompts[key] = {
    Positive: existing?.Positive || '',
    Negative: existing?.Negative || ''
  };
}

// --- Normalize deck-level geometries ---
const deckGeometries = {
  Title: {
    Font: deck.Geometries?.Title?.Font || '',
    Height: deck.Geometries?.Title?.Height || 18,
    Width: deck.Geometries?.Title?.Width || 660
  },
  Body: {
    Font: deck.Geometries?.Body?.Font || '',
    Height: deck.Geometries?.Body?.Height || 660,
    Width: deck.Geometries?.Body?.Width || 1060
  },
  Size: {
    Height: deck.Geometries?.Size?.Height || 680,
    Width: deck.Geometries?.Size?.Width || 1100
  },
  Images: {
    Height: deck.Geometries?.Images?.Height || 300,
    Width: deck.Geometries?.Images?.Width || 300
  }
};

// --- Normalize each card ---
const normalizedCards = [];

for (const card of (deck.Cards || [])) {
  const cardName = card.Card;
  const cardSlug = toFileSlug(cardName);
  const cardDir = card.Directory || BASE_DIR;

  // Build a lookup of existing records by orientation
  const existingRecords = {};
  for (const rec of (card.records || [])) {
    const orient = (rec.Orientation || '').toLowerCase();
    existingRecords[orient] = rec;
  }

  // Ensure all 3 orientations exist
  const normalizedRecords = [];
  for (const orientation of ORIENTATIONS) {
    const existing = existingRecords[orientation] || {};
    normalizedRecords.push(
      normalizeRecord(existing, cardName, cardSlug, orientation)
    );
  }

  // Build card-level prompts
  const cardPrompts = card.Prompts || {};
  const normalizedCardPrompts = {
    UprightImage: cardPrompts.UprightImage || buildImagePrompts(cardName, 'upright'),
    ReversedImage: cardPrompts.ReversedImage || buildImagePrompts(cardName, 'reversed')
  };

  normalizedCards.push({
    Card: cardName,
    Directory: cardDir,
    Assets: {
      UprightImage: card.Assets?.UprightImage || `CARD_${cardSlug}_Upright.png`,
      ReversedImage: card.Assets?.ReversedImage || `CARD_${cardSlug}_Reversed.png`
    },
    Prompts: normalizedCardPrompts,
    records: normalizedRecords
  });
}

// --- Assemble the normalized deck ---
const normalizedDeck = {
  Name: deck.Name || 'Standard',
  Version: DECK_VERSION,
  Prompts: deckPrompts,
  Geometries: deckGeometries,
  Assets: deckAssets,
  Cards: normalizedCards
};

return [{ json: normalizedDeck }];

